 395→const listMediaChunkForBucket = async(bucket, userId, offset, limit) => {
 396→    const folderPath = `user_id_${userId}`;
 397→
 398→    const {data: bucketItems, error: bucketError} = await supabase.storage
 399→        .from(bucket)
 400→        .list(folderPath, {
 401→            limit: limit,
 402→            offset: offset,
 403→            sortBy: {column: 'name', order: 'desc'}
 404→        });
 405→
 406→    if(bucketError){
 407→        return {
 408→            bucket: bucket,
 409→            nextOffset: offset,
 410→            exhausted: true,
 411→            items: [],
 412→            error: bucketError.message
 413→        };
 414→    }
 415→
 416→    const listedItems = Array.isArray(bucketItems) ? bucketItems : [];
 417→    const normalizedItems = listedItems
 418→        .filter((item) => item?.name && hasSupportedMediaExtension(item.name))
 419→        .map((item) => {
 420→            const path = `${folderPath}/${item.name}`;
 421→            const createdAt = item.created_at || item.updated_at || null;
 422→
 423→            return {
 424→                bucket: bucket,
 425→                path: path,
 426→                name: item.name,
 427→                createdAt: createdAt,
 428→                timestamp: parseMediaTimestamp(item)
 429→            };
 430→        });
 431→
 432→    return {
 433→        bucket: bucket,
 434→        nextOffset: offset + listedItems.length,
 435→        exhausted: listedItems.length < limit,
 436→        items: normalizedItems,
 437→        error: null
 438→    };
 439→};
 440→
 441→const hydrateMediaItems = async(items) => {
 442→    if(!Array.isArray(items) || items.length === 0){
 443→        return [];
 444→    }
 445→
 446→    const hydrated = await Promise.all(items.map(async(item) => {
 447→        const url = await resolveMediaUrl(item.bucket, item.path);
 448→        if(!url){
 449→            return null;
 450→        }
 451→
 452→        return {
 453→            id: `${item.bucket}-${item.path}`,
 454→            bucket: item.bucket,
 455→            path: item.path,
 456→            name: item.name,
 457→            createdAt: item.createdAt || null,
 458→            timestamp: item.timestamp || 0,
 459→            url: url
 460→        };
 461→    }));
 462→
 463→    return hydrated.filter(Boolean);
 464→};
