1214→    .from('bookmarks')
1215→    .select(`*,
1216→        journals(
1217→        id, created_at, user_id, content, title, 
1218→        comment_count: comments(count),
1219→        bookmark_count: bookmarks(count),
1220→
1221→        users(name, user_email, image_url, badge),
1222→
1223→        like_count: likes(count)
1224→        )
1225→        `, {count: 'exact'})
1226→
1227→    .eq('user_id', userId)
1228→    .order('created_at', {ascending: false})
1229→    .order('id', {ascending: false})
1230→    .limit(parseInt(limit) + 1)
1231→
1232→    if(before){
1233→        query = query.lt('created_at', before);
1234→    }
1235→
1236→    const {data: bookMarksData, error: errorBookmarks, count} = await query;
1237→
1238→    if(errorBookmarks){
1239→        console.error('supabase error:', errorBookmarks.message);
1240→        throw {status: 500, error: 'supabase error while fetching bookmarks'}
1241→    }
1242→
1243→    const journalIds = bookMarksData?.map((bookmark) => bookmark.journals.id);
1244→
1245→    if(journalIds.length === 0){
1246→        return {data: [], hasMore: false}
1247→    }
1248→
1249→    let hasLikedPromise;
1250→    let hasBookmarkedPromise;
1251→
1252→    if(journalIds){
1253→        hasLikedPromise = supabase
1254→        .from('likes')
1255→        .select('journal_id')
1256→        .in('journal_id', journalIds)
1257→        .eq('user_id', userId)
1258→
1259→        hasBookmarkedPromise = supabase
1260→        .from('bookmarks')
1261→        .select('journal_id')
1262→        .in('journal_id', journalIds)
1263→        .eq('user_id', userId)
1264→    }
1265→
1266→    const [hasLiked, hasBookMarked] = await Promise.all([
1267→        hasLikedPromise, hasBookmarkedPromise
1268→    ])
1269→
1270→    const {data: hasLikedResult, error: errorHasLikedResult} = hasLiked;
1271→    const {data: hasBookMarkedResult, error: errorHasbookmarkedResult} = hasBookMarked;
1272→
1273→    if(errorHasLikedResult || errorHasbookmarkedResult){
1274→        console.error('supabase error while fetching data:', errorHasLikedResult.message || errorHasbookmarkedResult.message);
1275→        throw {status: 500, error: 'supabase error while fetching data'};
1276→    }
1277→    
1278→    const userHasLikedSet = new Set(hasLikedResult.map((journal) => journal.journal_id) || []);
1279→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id) || []);
1280→
1281→    const hasMore = bookMarksData.length > paresedLimit;
1282→
1283→
1284→    const formattedData = bookMarksData.map((b) => ({
1285→        ...b,
1286→        has_liked: userHasLikedSet.has(b.journals.id),
1287→        has_bookmarked: userHasBookmarkedSet.has(b.journals.id),
1288→    }))
1289→
1290→    const slicedData = hasMore ? formattedData.splice(0, paresedLimit) : formattedData;
1291→
1292→    return {
1293→        bookmarks: slicedData,
1294→        hasMore: hasMore,
1295→        totalBookmarks: before ? null : count
1296→    }
1297→}
